SELECT attraction_name
FROM attractions
WHERE status = 'Open';

SELECT attraction_name
FROM attractions
WHERE capacity = (SELECT MAX(capacity) FROM attractions);

SELECT COUNT(*) AS open_attractions_count
FROM attractions
WHERE status = 'Open';

SELECT attraction_name 
FROM attractions 
ORDER BY attraction_name;

SELECT ride_type_name, average_duration
FROM ride_types
ORDER BY average_duration DESC;

SELECT attraction_name
FROM attractions
ORDER BY attraction_name;
